/**
 * Tests for v0.3 query extractor improvements:
 * - Multi-word entity extraction
 * - CamelCase splitting
 * - Co-occurrence (RAKE) scoring
 * - Abbreviation expansion
 * - Casual filter entity override
 *
 * Run: npx tsx test/query-extractor-v03.test.ts
 */
import { extractQueries, hasSubstantiveEntities, setCustomAbbreviations } from "../src/query-extractor.js";

let passed = 0;
let failed = 0;

function assert(condition: boolean, name: string) {
  if (condition) {
    passed++;
    console.log(`  ✅ ${name}`);
  } else {
    failed++;
    console.log(`  ❌ ${name}`);
  }
}

async function runTests() {
  // === Multi-word Entity Extraction ===
  console.log("\n👥 Multi-word Entity Extraction");

  const tomMerkle = extractQueries("Tom Merkle was working on the fleet system");
  const nounQuery = tomMerkle.queries.find(q => q.includes("Tom Merkle"));
  assert(nounQuery !== undefined, '"Tom Merkle" extracted as single entity');

  const mentalModel = extractQueries("The Mental Model tool is almost done");
  const mmQuery = mentalModel.queries.find(q => q.includes("Mental Model"));
  assert(mmQuery !== undefined, '"Mental Model" extracted as single entity');

  // Three-word entity
  const fleetManager = extractQueries("I need to check the Fleet Manager API for errors");
  const fmQuery = fleetManager.queries.find(q => q.includes("Fleet Manager API"));
  assert(fmQuery !== undefined, '"Fleet Manager API" extracted as single entity');

  // === CamelCase Splitting ===
  console.log("\n🐪 CamelCase Splitting");

  const oathKeeper = extractQueries("How is OathKeeper doing?");
  const hasOathKeeper = oathKeeper.queries.some(q => q.includes("OathKeeper"));
  const hasOathSpace = oathKeeper.queries.some(q => q.includes("Oath Keeper"));
  assert(hasOathKeeper, "OathKeeper preserved as-is");
  assert(hasOathSpace, "Oath Keeper split variant also generated");

  const keyBert = extractQueries("Does KeyBERT work in TypeScript?");
  const hasKeyBert = keyBert.queries.some(q => q.includes("KeyBERT"));
  assert(hasKeyBert, "KeyBERT preserved (all-caps suffix treated as one segment)");

  // === Abbreviation Expansion ===
  console.log("\n📖 Abbreviation Expansion");

  // Short message with abbreviation
  const prQuery = extractQueries("Check the PR status for fleet-rest");
  const hasPullRequest = prQuery.queries.some(q => q.toLowerCase().includes("pull request"));
  assert(hasPullRequest, '"PR" expanded to "pull request" in queries');

  const e2eQuery = extractQueries("We need E2E tests for the payment flow");
  const hasEndToEnd = e2eQuery.queries.some(q => q.toLowerCase().includes("end-to-end"));
  assert(hasEndToEnd, '"E2E" expanded to "end-to-end" in queries');

  // === Proper Noun Strategy ===
  console.log("\n🏷️ Proper Noun Strategy");

  const properResult = extractQueries("Tell me about OathKeeper");
  assert(properResult.strategy === "proper-nouns", "short message with proper noun → proper-nouns strategy");

  const verbatimResult = extractQueries("what happened yesterday with the builds");
  assert(verbatimResult.strategy === "verbatim", "short message without proper nouns → verbatim strategy");

  // === Entity Detection (hasSubstantiveEntities) ===
  console.log("\n🔍 hasSubstantiveEntities");

  assert(hasSubstantiveEntities("OathKeeper status?") === true, "OathKeeper is substantive");
  assert(hasSubstantiveEntities("Tom Merkle mentioned it") === true, "Tom Merkle is substantive");
  assert(hasSubstantiveEntities("check the PR") === true, "PR is a known abbreviation");
  assert(hasSubstantiveEntities("hey how goes") === false, "casual greeting is not substantive");
  assert(hasSubstantiveEntities("yeah sure thing") === false, "agreement is not substantive");
  assert(hasSubstantiveEntities("ok cool") === false, "ok cool is not substantive");

  // === Casual Filter Override ===
  console.log("\n💬 Casual Filter Entity Override");

  // These SHOULD produce queries (entities present despite casual prefix)
  const howsOathkeeper = extractQueries("How's OathKeeper going?");
  assert(howsOathkeeper.queries.length > 0, '"How\'s OathKeeper going?" produces queries (not filtered as casual)');

  const heyFleet = extractQueries("Hey, what's the Fleet Manager status?");
  assert(heyFleet.queries.length > 0, '"Hey, what\'s the Fleet Manager status?" produces queries');

  // These SHOULD be filtered (truly casual, no entities)
  // Note: extractQueries itself doesn't filter — the RecallEngine does via isCasualMessage.
  // We test the entity detection function which the filter uses.
  assert(hasSubstantiveEntities("How's it going?") === false, '"How\'s it going?" has no entities → would be filtered');
  assert(hasSubstantiveEntities("hey what's up") === false, '"hey what\'s up" has no entities → would be filtered');

  // === RAKE Co-occurrence Scoring ===
  console.log("\n📊 RAKE Co-occurrence Scoring");

  // In a medium-length message, key phrases should be extracted from stop-word boundaries
  const mediumMsg = "The fleet management system has a settlement calculation bug. " +
    "The database queries are timing out under heavy load and the " +
    "meter data imports from February are conflicting with the new config.";

  const mediumResult = extractQueries(mediumMsg);
  assert(mediumResult.queries.length >= 2, "medium message produces 2+ queries");
  // Key phrases should include multi-word candidates from stop-word splitting
  // "fleet management system", "settlement calculation bug", "database queries", etc.
  const allQueries = mediumResult.queries.join(" ").toLowerCase();
  assert(
    allQueries.includes("fleet") || allQueries.includes("settlement") || allQueries.includes("database"),
    "RAKE extracts domain-relevant terms from medium message"
  );

  // === Custom Abbreviations ===
  console.log("\n🔧 Custom Abbreviations");

  setCustomAbbreviations({ "hbfr": "hashbranch fleet rest", "cla": "clankers" });
  const customResult = extractQueries("Check the HBFR deployment");
  const hasCustomExpansion = customResult.queries.some(q => q.toLowerCase().includes("hashbranch fleet rest"));
  assert(hasCustomExpansion, "custom abbreviation HBFR expanded");

  // Reset custom abbreviations
  setCustomAbbreviations({});

  // === Edge Cases ===
  console.log("\n🧪 Edge Cases");

  const empty = extractQueries("");
  assert(empty.queries.length === 0, "empty string → no queries");

  const justStopWords = extractQueries("the and or but if so");
  assert(justStopWords.queries.length >= 1, "stop-word-only message still produces verbatim query");

  const singleWord = extractQueries("OathKeeper");
  assert(singleWord.queries.length >= 1, "single proper noun produces query");
  assert(singleWord.queries.some(q => q.includes("OathKeeper")), "single proper noun preserved");

  // === Summary ===
  console.log(`\n${"=".repeat(40)}`);
  console.log(`Results: ${passed} passed, ${failed} failed`);
  if (failed > 0) process.exit(1);
}

runTests().catch((err) => {
  console.error("Test error:", err);
  process.exit(1);
});
